  "uiTreePath": ".arkpilot/designs/ui-tree.json",
  "dataModel": {
    "enums": {
      "RecordCategory": ["meeting", "equipment", "violation", "environment", "other"],
      "RecordStatus": ["open", "in_progress", "closed"],
      "HazardLevel": ["low", "medium", "high"],
      "HazardStatus": ["reported", "rectifying", "rectified", "accepted"],
      "PatrolPointStatus": ["pending", "normal", "abnormal"],
      "StatsPeriod": ["today", "week", "month"],
      "CheckinResult": ["normal", "abnormal"]
    },
    "entities": {
      "RecordItem": {
        "id": "string",
        "title": "string",
        "category": "RecordCategory",
        "note": "string",
        "status": "RecordStatus",
        "createdAt": "number (epoch ms)"
      },
      "HazardItem": {
        "id": "string",
        "title": "string",
        "level": "HazardLevel",
        "location": "string",
        "description": "string",
        "photoUri": "string (nullable)",
        "status": "HazardStatus",
        "createdAt": "number (epoch ms)"
      },
      "PatrolPoint": {
        "id": "string",
        "name": "string",
        "locationHint": "string",
        "status": "PatrolPointStatus",
        "lastCheckinAt": "number (epoch ms, nullable)",
        "lastNote": "string"
      },
      "Contact": {
        "id": "string",
        "name": "string",
        "phone": "string",
        "role": "string"
      },
      "TodoItem": {
        "id": "string",
        "title": "string",
        "kind": "string (hazard|patrol)",
        "level": "string (nullable)",
        "status": "string",
        "refId": "string"
      },
      "Profile": {
        "name": "string",
        "role": "string"
      }
    },
    "formState": {
      "draft.record": { "title": "string", "category": "RecordCategory", "note": "string" },
      "draft.hazard": { "title": "string", "level": "HazardLevel", "location": "string", "description": "string", "photoUri": "string (nullable)" },
      "draft.contact": { "id": "string (nullable for create)", "name": "string", "phone": "string", "role": "string" },
      "draft.checkin": { "pointId": "string", "result": "CheckinResult", "note": "string" }
    },
    "computedState": {
      "stats.hazardCount": "hazards created within selected period",
      "stats.patrolRate": "percent of patrol points checked-in (normal+abnormal) over total",
      "stats.rectifyRate": "percent of hazards rectified+accepted over total hazards",
      "stats.pendingCount": "hazards with status reported|rectifying AND level high within period (pending high-priority)",
      "todos": "derived: high-priority open hazards + pending patrol points"
    },
    "persistence": {
      "strategy": "local Preferences-backed store; key/value JSON blobs per collection (records, hazards, patrolPoints, contacts, profile)",
      "scope": "durable user data; transient UI/draft state stays in-memory only",
      "seed": "no seeded demo data; collections start empty and show empty states"
    }
  },
  "services": {
    "PrefStorage": {
      "responsibility": "Wrap @ohos.data.preferences; load/save named collections as JSON strings; provide get/set/remove.",
      "usedBy": ["AppStore"]
    },
    "AppStore": {
      "responsibility": "Central observable store. Owns all collections, draft state, derived stats, and exposes event methods matching every ui-tree.json event. Persists through PrefStorage.",
      "state": ["records", "hazards", "patrolPoints", "contacts", "profile", "drafts", "stats period"],
      "notes": "Initialized once on app launch (EntryAbility / first page); provides AppStorage keys for UI binding."
    },
    "CallService": {
      "responsibility": "Adapt @ohos.telephony.call (or system dialer) for one-tap contact dialing. Stubbed to opening dialer via want when telephony permission is unavailable.",
      "usedBy": ["Contacts flow"]
    },
    "PhotoService": {
      "responsibility": "Adapt @ohos.multimedia.camera / photoAccessHelper for hazard photo capture or pick. Stubbed when unavailable; returns a placeholder URI in private dir.",
      "usedBy": ["Hazard report flow"]
    }
  },
  "stateMachine": {
    "AppLifecycle": {
      "states": ["uninitialized", "ready"],
      "transitions": ["uninitialized -> ready on init() after PrefStorage load"]
    },
    "Hazard": {
      "states": ["reported", "rectifying", "rectified", "accepted"],
      "transitions": [
        "reported -> rectifying (update-rectify-status)",
        "rectifying -> rectified (update-rectify-status)",
        "rectified -> accepted (update-rectify-status)"
      ]
    },
    "PatrolPoint": {
      "states": ["pending", "normal", "abnormal"],
      "transitions": [
        "pending -> normal|abnormal on submit-checkin",
        "normal|abnormal -> normal|abnormal on re-checkin (last result updated)"
      ]
    },
    "Record": {
      "states": ["open", "in_progress", "closed"],
      "transitions": ["open -> in_progress -> closed via direct status edits (MVP: created as open)"]
    },
    "StatsPeriod": {
      "states": ["today", "week", "month"],
      "transitions": ["any -> any on change-stats-period; recomputes derived stats"]
    }
  },
  "interactionFlows": [
    {
      "id": "flow-save-record",
      "trigger": "save-record (add-record-sheet)",
      "inputs": ["draft.record.title", "draft.record.category", "draft.record.note"],
      "steps": [
        "validate title non-empty",
        "generate id + createdAt",
        "append to records with status open",
        "persist records",
        "reset draft.record",
        "close add-record sheet"
      ],
      "errors": ["title empty -> reject save, keep sheet open, surface validation message"]
    },
    {
      "id": "flow-filter-records",
      "trigger": "filter-record-status + search",
      "steps": ["compute filtered records by status + search substring"],
      "expectedState": "records-list reflects filter; empty-state shown when none"
    },
    {
      "id": "flow-submit-hazard",
      "trigger": "submit-hazard (add-hazard-sheet)",
      "inputs": ["draft.hazard.*"],
      "steps": [
        "validate title non-empty",
        "generate id + createdAt",
        "status reported",
        "append to hazards",
        "persist hazards",
        "reset draft.hazard",
        "close sheet"
      ],
      "errors": ["title empty -> reject"]
    },
    {
      "id": "flow-update-rectify",
      "trigger": "update-rectify-status (hazard-detail-sheet)",
      "steps": ["set hazard.status to chosen next state", "persist hazards", "recompute stats/todos"],
      "expectedState": "hazard-detail-rectify-status reflects new value"
    },
    {
      "id": "flow-filter-hazards",
      "trigger": "filter-hazard-level + filter-hazard-status",
      "steps": ["compute filtered hazards by level + status"],
      "expectedState": "hazards-list reflects filter; empty-state when none"
    },
    {
      "id": "flow-start-patrol",
      "trigger": "start-patrol",
      "steps": ["ensure patrol points exist; if empty show patrol-empty-state"]
    },
    {
      "id": "flow-submit-checkin",
      "trigger": "submit-checkin (patrol-checkin-sheet)",
      "inputs": ["draft.checkin.pointId", "draft.checkin.result", "draft.checkin.note"],
      "steps": [
        "locate patrol point by pointId",
        "set status = result, lastCheckinAt = now, lastNote = note",
        "persist patrolPoints",
        "reset draft.checkin",
        "close sheet",
        "recompute patrol progress + stats"
      ]
    },
    {
      "id": "flow-save-contact",
      "trigger": "save-contact (add-contact-sheet)",
      "inputs": ["draft.contact.*"],
      "steps": [
        "validate name + phone non-empty",
        "if id present -> update existing, else generate id and append",
        "persist contacts",
        "reset draft.contact",
        "close sheet"
      ],
      "errors": ["name or phone empty -> reject"]
    },
    {
      "id": "flow-call-contact",
      "trigger": "call-contact",
      "steps": ["invoke CallService.dial(phone)"],
      "errors": ["dialer unavailable -> record no-op, do not crash"]
    },
    {
      "id": "flow-change-stats-period",
      "trigger": "change-stats-period (home-period-segment)",
      "steps": ["set stats period", "recompute hazardCount / patrolRate / rectifyRate / pendingCount / todos"],
      "expectedState": "home-stat-* reflect new period"
    }
  ],
  "testTargets": [
    "home-stat-hazards",
    "home-stat-patrol-rate",
    "home-stat-rectify-rate",
    "home-stat-pending",
    "home-todo-list",
    "home-todo-empty",
    "records-list",
    "records-empty-state",
    "hazards-list",
    "hazards-empty-state",
    "patrol-point-list",
    "patrol-empty-state",
    "contacts-list",
    "contacts-empty-state"
  ],
  "changeRequests": []
}

