// Types.ets
//
// Shared domain types and enums for the 平安扣 (Pinankou) app.
// Pure data layer: no UI dependencies. Consumed by services/AppStore and pages.

// ---- Enums (string-literal unions; JSON-friendly) ----
export type RecordCategory = 'meeting' | 'equipment' | 'violation' | 'environment' | 'other';
export type RecordStatus = 'open' | 'in_progress' | 'closed';
export type HazardLevel = 'low' | 'medium' | 'high';
export type HazardStatus = 'reported' | 'rectifying' | 'rectified' | 'accepted';
export type PatrolPointStatus = 'pending' | 'normal' | 'abnormal';
export type StatsPeriod = 'today' | 'week' | 'month';
export type CheckinResult = 'normal' | 'abnormal';

// ---- Entities ----
export interface RecordItem {
  id: string;
  title: string;
  category: RecordCategory;
  note: string;
  status: RecordStatus;
  createdAt: number;
}

export interface HazardItem {
  id: string;
  title: string;
  level: HazardLevel;
  location: string;
  description: string;
  photoUri: string;
  status: HazardStatus;
  createdAt: number;
}

export interface PatrolPoint {
  id: string;
  name: string;
  locationHint: string;
  status: PatrolPointStatus;
  lastCheckinAt: number;
  lastNote: string;
}

export interface Contact {
  id: string;
  name: string;
  phone: string;
  role: string;
}

export interface Profile {
  name: string;
  role: string;
}

export interface TodoItem {
  id: string;
  title: string;
  kind: string; // 'hazard' | 'patrol'
  level: string;
  status: string;
  refId: string;
}

// ---- Drafts (form state; transient, not persisted) ----
export interface RecordDraft {
  title: string;
  category: RecordCategory;
  note: string;
}

export interface HazardDraft {
  title: string;
  level: HazardLevel;
  location: string;
  description: string;
  photoUri: string;
}

export interface ContactDraft {
  id: string;
  name: string;
  phone: string;
  role: string;
}

export interface CheckinDraft {
  pointId: string;
  result: CheckinResult;
  note: string;
}

// ---- Display labels (logic-only; pages may reuse) ----
export class Labels {
  static recordCategory(c: RecordCategory): string {
    if (c === 'meeting') {
      return '班前会议';
    } else if (c === 'equipment') {
      return '设备检查';
    } else if (c === 'violation') {
      return '违章记录';
    } else if (c === 'environment') {
      return '环境检查';
    }
    return '其他';
  }

  static recordStatus(s: RecordStatus): string {
    if (s === 'open') {
      return '待处理';
    } else if (s === 'in_progress') {
      return '进行中';
    }
    return '已关闭';
  }

  static hazardLevel(l: HazardLevel): string {
    if (l === 'low') {
      return '低风险';
    } else if (l === 'medium') {
      return '中风险';
    }
    return '高风险';
  }

  static hazardStatus(s: HazardStatus): string {
    if (s === 'reported') {
      return '待整改';
    } else if (s === 'rectifying') {
      return '整改中';
    } else if (s === 'rectified') {
      return '已整改';
    }
    return '已验收';
  }

  static patrolStatus(s: PatrolPointStatus): string {
    if (s === 'normal') {
      return '正常';
    } else if (s === 'abnormal') {
      return '异常';
    }
    return '未打卡';
  }

  // Ordered rectify workflow for hazard-detail status picker.
  static readonly HAZARD_STATUS_ORDER: HazardStatus[] = ['reported', 'rectifying', 'rectified', 'accepted'];
}

