// CallService.ets
//
// Adapter for one-tap emergency contact dialing.
// Uses the system dialer via a Want when telephony permission/direct call is
// unavailable. Headless: no UI dependencies.

import { Want } from '@kit.AbilityKit';
import { common } from '@kit.AbilityKit';

export class CallService {
  private context: common.Context | null = null;

  setContext(context: common.Context): void {
    this.context = context;
  }

  // Returns true if the dial action was dispatched. Never throws.
  dial(phone: string): boolean {
    if (!phone || !this.context) {
      return false;
    }
    const cleaned = phone.replace(/[^0-9+*#]/g, '');
    if (!cleaned) {
      return false;
    }
    try {
      const want: Want = {
        action: 'ohos.want.action.call',
        parameters: {
          'ohos.telephony.phone.number': cleaned,
        },
      } as Want;
      (this.context as common.UIAbilityContext).startAbility(want);
      return true;
    } catch (e) {
      return false;
    }
  }
}

