// AppStore.ets
//
// Central observable store for 平安扣 (Pinankou).
// Owns all collections + draft state, exposes the event methods that map 1:1
// to ui-behavior.json interaction flows, and persists durable data through
// PrefStorage. UI binds via AppStorage keys (set on init).
//
// AppStorage keys:
//   'pinankou.records'   : RecordItem[]
//   'pinankou.hazards'   : HazardItem[]
//   'pinankou.patrol'    : PatrolPoint[]
//   'pinankou.contacts'  : Contact[]
//   'pinankou.profile'   : Profile
//   'pinankou.period'    : StatsPeriod
//   'pinankou.stats'     : StatsSnapshot (computed)

import { common } from '@kit.AbilityKit';
import { PrefStorage } from './PrefStorage';
import { CallService } from './CallService';
import {
  RecordItem,
  HazardItem,
  PatrolPoint,
  Contact,
  Profile,
  TodoItem,
  RecordDraft,
  HazardDraft,
  ContactDraft,
  CheckinDraft,
  HazardStatus,
  HazardLevel,
  StatsPeriod,
  CheckinResult,
} from '../common/Types';

export interface StatsSnapshot {
  hazardCount: number;
  patrolRate: number;
  rectifyRate: number;
  pendingCount: number;
}

const KEY_RECORDS = 'pinankou.records';
const KEY_HAZARDS = 'pinankou.hazards';
const KEY_PATROL = 'pinankou.patrol';
const KEY_CONTACTS = 'pinankou.contacts';
const KEY_PROFILE = 'pinankou.profile';
const KEY_PERIOD = 'pinankou.period';
const KEY_STATS = 'pinankou.stats';

const DEFAULT_PROFILE: Profile = { name: '当前用户', role: '安全员' };

// Master data: a predefined patrol route is reference data, not demo
// transactional data. Seeded once only when no patrol points are persisted.
const DEFAULT_PATROL_POINTS: PatrolPoint[] = [
  { id: 'patrol_p1', name: '1号配电室', locationHint: 'A区-地下一层', status: 'pending', lastCheckinAt: 0, lastNote: '' },
  { id: 'patrol_p2', name: '原料仓库', locationHint: 'B区-一层东侧', status: 'pending', lastCheckinAt: 0, lastNote: '' },
  { id: 'patrol_p3', name: '生产车间主线', locationHint: 'C区-二层', status: 'pending', lastCheckinAt: 0, lastNote: '' },
  { id: 'patrol_p4', name: '消防控制室', locationHint: '主楼-一层中庭', status: 'pending', lastCheckinAt: 0, lastNote: '' },
];

export class AppStore {
  private prefs: PrefStorage = new PrefStorage();
  private callService: CallService = new CallService();
  private ready: boolean = false;

  private records: RecordItem[] = [];
  private hazards: HazardItem[] = [];
  private patrol: PatrolPoint[] = [];
  private contacts: Contact[] = [];
  private profile: Profile = DEFAULT_PROFILE;
  private period: StatsPeriod = 'today';

  // ---- Lifecycle ----
  async init(context: common.Context): Promise<void> {
    if (this.ready) {
      return;
    }
    this.callService.setContext(context);
    await this.prefs.init(context);

    const rawRecords = await this.prefs.get(KEY_RECORDS, '');
    const rawHazards = await this.prefs.get(KEY_HAZARDS, '');
    const rawPatrol = await this.prefs.get(KEY_PATROL, '');
    const rawContacts = await this.prefs.get(KEY_CONTACTS, '');
    const rawProfile = await this.prefs.get(KEY_PROFILE, '');
    const rawPeriod = await this.prefs.get(KEY_PERIOD, '');

    this.records = this.parseArr<RecordItem>(rawRecords);
    this.hazards = this.parseArr<HazardItem>(rawHazards);
    this.patrol = this.parseArr<PatrolPoint>(rawPatrol);
    this.contacts = this.parseArr<Contact>(rawContacts);
    this.profile = rawProfile ? this.parseObj<Profile>(rawProfile) : DEFAULT_PROFILE;
    this.period = rawPeriod ? (rawPeriod as StatsPeriod) : 'today';

    // Seed patrol route once if the user has never persisted any.
    if (this.patrol.length === 0) {
      this.patrol = DEFAULT_PATROL_POINTS.map((p) => {
        return {
          id: p.id,
          name: p.name,
          locationHint: p.locationHint,
          status: p.status,
          lastCheckinAt: p.lastCheckinAt,
          lastNote: p.lastNote,
        } as PatrolPoint;
      });
      await this.prefs.put(KEY_PATROL, JSON.stringify(this.patrol));
    }

    this.ready = true;
    this.publishAll();
  }

  // ---- Public accessors for headless use / future pages ----
  getRecords(): RecordItem[] { return this.records; }
  getHazards(): HazardItem[] { return this.hazards; }
  getPatrol(): PatrolPoint[] { return this.patrol; }
  getContacts(): Contact[] { return this.contacts; }
  getProfile(): Profile { return this.profile; }
  getPeriod(): StatsPeriod { return this.period; }
  getCallService(): CallService { return this.callService; }

  // ---- Record flows ----
  saveRecord(draft: RecordDraft): boolean {
    const title = draft.title.trim();
    if (!title) {
      return false;
    }
    const item: RecordItem = {
      id: this.genId('rec'),
      title: title,
      category: draft.category,
      note: draft.note.trim(),
      status: 'open',
      createdAt: Date.now(),
    };
    this.records = [item].concat(this.records);
    this.persistAndPublish(KEY_RECORDS, this.records);
    this.recomputeStats();
    return true;
  }

  filterRecords(statusFilter: string, search: string): RecordItem[] {
    const s = search.trim();
    return this.records.filter((r) => {
      const statusOk = statusFilter === 'all' || statusFilter === '' ? true : r.status === statusFilter;
      const searchOk = s.length === 0 ? true : r.title.includes(s) || r.note.includes(s);
      return statusOk && searchOk;
    });
  }

  // ---- Hazard flows ----
  submitHazard(draft: HazardDraft): boolean {
    const title = draft.title.trim();
    if (!title) {
      return false;
    }
    const item: HazardItem = {
      id: this.genId('hz'),
      title: title,
      level: draft.level,
      location: draft.location.trim(),
      description: draft.description.trim(),
      photoUri: draft.photoUri,
      status: 'reported',
      createdAt: Date.now(),
    };
    this.hazards = [item].concat(this.hazards);
    this.persistAndPublish(KEY_HAZARDS, this.hazards);
    this.recomputeStats();
    return true;
  }

  updateRectifyStatus(id: string, status: HazardStatus): void {
    let changed = false;
    this.hazards = this.hazards.map((h) => {
      if (h.id === id && h.status !== status) {
        changed = true;
        const updated: HazardItem = {
          id: h.id,
          title: h.title,
          level: h.level,
          location: h.location,
          description: h.description,
          photoUri: h.photoUri,
          status: status,
          createdAt: h.createdAt,
        };
        return updated;
      }
      return h;
    });
    if (changed) {
      this.persistAndPublish(KEY_HAZARDS, this.hazards);
      this.recomputeStats();
    }
  }

  filterHazards(levelFilter: string, statusFilter: string): HazardItem[] {
    return this.hazards.filter((h) => {
      const levelOk = levelFilter === 'all' || levelFilter === '' ? true : h.level === levelFilter;
      const statusOk = statusFilter === 'all' || statusFilter === '' ? true : h.status === statusFilter;
      return levelOk && statusOk;
    });
  }

  // ---- Patrol flows ----
  startPatrol(): void {
    // No-op beyond ensuring data is loaded; UI shows empty-state when no points.
    this.publish(KEY_PATROL, this.patrol);
  }

  submitCheckin(draft: CheckinDraft): boolean {
    let changed = false;
    this.patrol = this.patrol.map((p) => {
      if (p.id === draft.pointId) {
        changed = true;
        const updated: PatrolPoint = {
          id: p.id,
          name: p.name,
          locationHint: p.locationHint,
          status: draft.result,
          lastCheckinAt: Date.now(),
          lastNote: draft.note.trim(),
        };
        return updated;
      }
      return p;
    });
    if (changed) {
      this.persistAndPublish(KEY_PATROL, this.patrol);
      this.recomputeStats();
    }
    return changed;
  }

  patrolProgress(): number {
    const total = this.patrol.length;
    if (total === 0) {
      return 0;
    }
    const done = this.patrol.filter((p) => p.status === 'normal' || p.status === 'abnormal').length;
    return Math.round((done / total) * 100);
  }

  // ---- Contact flows ----
  saveContact(draft: ContactDraft): boolean {
    const name = draft.name.trim();
    const phone = draft.phone.trim();
    if (!name || !phone) {
      return false;
    }
    if (draft.id) {
      let changed = false;
      this.contacts = this.contacts.map((c) => {
        if (c.id === draft.id) {
          changed = true;
          const updated: Contact = {
            id: c.id,
            name: name,
            phone: phone,
            role: draft.role.trim(),
          };
          return updated;
        }
        return c;
      });
      if (changed) {
        this.persistAndPublish(KEY_CONTACTS, this.contacts);
      }
      return changed;
    }
    const item: Contact = {
      id: this.genId('ct'),
      name: name,
      phone: phone,
      role: draft.role.trim(),
    };
    this.contacts = [item].concat(this.contacts);
    this.persistAndPublish(KEY_CONTACTS, this.contacts);
    return true;
  }

  callContact(phone: string): boolean {
    return this.callService.dial(phone);
  }

  // ---- Stats flow ----
  changeStatsPeriod(period: StatsPeriod): void {
    if (this.period === period) {
      return;
    }
    this.period = period;
    this.prefs.put(KEY_PERIOD, period);
    this.publish(KEY_PERIOD, period);
    this.recomputeStats();
  }

  computeTodos(): TodoItem[] {
    const todos: TodoItem[] = [];
    this.hazards.forEach((h) => {
      if ((h.status === 'reported' || h.status === 'rectifying')) {
        todos.push({
          id: `todo_hz_${h.id}`,
          title: h.title,
          kind: 'hazard',
          level: h.level,
          status: h.status,
          refId: h.id,
        });
      }
    });
    this.patrol.forEach((p) => {
      if (p.status === 'pending') {
        todos.push({
          id: `todo_pt_${p.id}`,
          title: p.name,
          kind: 'patrol',
          level: '',
          status: 'pending',
          refId: p.id,
        });
      }
    });
    return todos;
  }

  computeStats(period: StatsPeriod): StatsSnapshot {
    const windowStart = this.periodStart(period);
    const hazardCount = this.hazards.filter((h) => h.createdAt >= windowStart).length;
    const totalPatrol = this.patrol.length;
    const donePatrol = this.patrol.filter((p) => p.status === 'normal' || p.status === 'abnormal').length;
    const patrolRate = totalPatrol === 0 ? 0 : Math.round((donePatrol / totalPatrol) * 100);

    const totalHazards = this.hazards.length;
    const rectified = this.hazards.filter((h) => h.status === 'rectified' || h.status === 'accepted').length;
    const rectifyRate = totalHazards === 0 ? 0 : Math.round((rectified / totalHazards) * 100);

    const pendingCount = this.hazards.filter((h) =>
      (h.status === 'reported' || h.status === 'rectifying') && h.level === 'high').length;

    return { hazardCount, patrolRate, rectifyRate, pendingCount };
  }

  private recomputeStats(): void {
    const snap = this.computeStats(this.period);
    this.publish(KEY_STATS, snap);
  }

  private periodStart(period: StatsPeriod): number {
    const now = Date.now();
    if (period === 'today') {
      const d = new Date(now);
      d.setHours(0, 0, 0, 0);
      return d.getTime();
    } else if (period === 'week') {
      return now - 7 * 24 * 60 * 60 * 1000;
    }
    return now - 30 * 24 * 60 * 60 * 1000;
  }

  // ---- Helpers ----
  private genId(prefix: string): string {
    return `${prefix}_${Date.now()}_${Math.floor(Math.random() * 1000000)}`;
  }

  private persistAndPublish<T>(key: string, value: T[]): void {
    this.prefs.put(key, JSON.stringify(value));
    this.publish(key, value);
  }

  private publish(key: string, value: Object): void {
    AppStorage.setOrCreate(key, value);
    AppStorage.set(key, value);
  }

  private publishAll(): void {
    this.publish(KEY_RECORDS, this.records);
    this.publish(KEY_HAZARDS, this.hazards);
    this.publish(KEY_PATROL, this.patrol);
    this.publish(KEY_CONTACTS, this.contacts);
    this.publish(KEY_PROFILE, this.profile);
    this.publish(KEY_PERIOD, this.period);
    this.recomputeStats();
  }

  private parseArr<T>(raw: string): T[] {
    if (!raw) {
      return [];
    }
    try {
      const obj = JSON.parse(raw);
      return Array.isArray(obj) ? (obj as T[]) : [];
    } catch (e) {
      return [];
    }
  }

  private parseObj<T>(raw: string): T {
    try {
      return JSON.parse(raw) as T;
    } catch (e) {
      return {} as T;
    }
  }
}

// Module-level singleton; pages and controllers import `appStore`.
export const appStore: AppStore = new AppStore();

