// PrefStorage.ets
//
// Thin wrapper over @ohos.data.preferences (via @kit.ArkData).
// Persists each Pinankou collection as a JSON string under a stable key.
// Headless service: no UI dependencies. All I/O is guarded so failures
// degrade to defaults rather than crashing callers.

import { preferences } from '@kit.ArkData';
import { common } from '@kit.AbilityKit';

const STORE_NAME = 'pinankou_store';

export class PrefStorage {
  private store: preferences.Preferences | null = null;

  async init(context: common.Context): Promise<void> {
    try {
      this.store = await preferences.getPreferences(context, STORE_NAME);
    } catch {
      this.store = null;
    }
  }

  private isReady(): boolean {
    return this.store !== null;
  }

  async put(key: string, value: string): Promise<void> {
    if (!this.isReady()) {
      return;
    }
    try {
      await this.store!.put(key, value);
      await this.store!.flush();
    } catch {
      // best-effort persistence; ignore storage failures
    }
  }

  async get(key: string, def: string): Promise<string> {
    if (!this.isReady()) {
      return def;
    }
    try {
      const v = await this.store!.get(key, def);
      return (v !== null && v !== undefined) ? (v as string) : def;
    } catch {
      return def;
    }
  }
}

