private parseArr<T>(raw: string): T[] {
  if (!raw) {
    return [];
  }
  try {
    const obj = JSON.parse(raw);
    return Array.isArray(obj) ? (obj as T[]) : [];
  } catch {
    return [];
  }
}

private parseProfile(raw: string): Profile {
  if (!raw) {
    return { name: DEFAULT_PROFILE.name, role: DEFAULT_PROFILE.role };
  }

